svg.script:
var seed = 123;
function rand() { seed = (seed * 16807 + 0) % 2147483647; return (seed - 1) / 2147483646; }
function noise() { return (rand() - 0.5) * 2; }

var W = 720, H = 230, OX = 50, OY = 20;
var midY = OY + H / 2;
var totalTime = 10;
var samplesPerSec = 50;
var totalSamples = totalTime * samplesPerSec;

// 3m walk: rest 0-2.5s, walking 2.5-8.5s (gradual onset/offset), rest 8.5-10s
function getEnvelope(t) {
  if (t < 2.5) return 0;
  if (t > 8.5) return 0;
  // Gradual onset 2.5-3.5
  if (t < 3.5) {
    var f = (t - 2.5) / 1.0;
    return f * f; // quadratic ramp up
  }
  // Gradual offset 7.5-8.5
  if (t > 7.5) {
    var f = (8.5 - t) / 1.0;
    return f * f; // quadratic ramp down
  }
  return 1.0;
}

function genSignal(ampWalk, freqWalk, phaseOff, noiseScale) {
  var pts = [];
  for (var i = 0; i < totalSamples; i++) {
    var t = i / samplesPerSec;
    var env = getEnvelope(t);
    var val;

    if (env < 0.01) {
      // Rest
      val = 0.012 * Math.sin(2 * Math.PI * 0.08 * t + phaseOff) + noise() * 0.006;
    } else {
      // Walking: rhythmic arm swing pattern
      val = env * ampWalk * (
        Math.sin(2 * Math.PI * freqWalk * t + phaseOff) * 0.65 +
        Math.sin(2 * Math.PI * freqWalk * 2 * t + phaseOff * 0.7) * 0.2 +
        Math.sin(2 * Math.PI * freqWalk * 3 * t + phaseOff * 1.4) * 0.08 +
        Math.sin(2 * Math.PI * freqWalk * 0.5 * t + phaseOff * 2.1) * 0.07
      ) + noise() * noiseScale * (0.4 + env * 0.6);
    }
    pts.push(val);
  }
  return pts;
}

var xSig = genSignal(0.22, 1.8, 0, 0.018);
var ySig = genSignal(0.14, 1.8, 1.6, 0.013);
var zSig = genSignal(0.20, 1.8, 3.2, 0.016);

function toPath(sig) {
  var maxAmp = 0.35;
  var d = "";
  for (var i = 0; i < sig.length; i++) {
    var x = OX + (i / totalSamples) * W;
    var y = midY - (sig[i] / maxAmp) * (H / 2 - 10);
    d += (i === 0 ? "M" : "L") + x.toFixed(1) + "," + y.toFixed(1);
  }
  return d;
}

document.getElementById("pathX").setAttribute("d", toPath(xSig));
document.getElementById("pathY").setAttribute("d", toPath(ySig));
document.getElementById("pathZ").setAttribute("d", toPath(zSig));
